#include<bits/stdc++.h>
using namespace std;
int n,m;
int dx[4]={0,-1,0,1};
int dy[4]={1,0,-1,0};
bool vis[1001][1001];
int mp[1001][1001],best[1001][1001],ans=INT_MAX;
void dfs(int x,int y,int cost,bool flag)
{
    if(cost>=best[x][y])
    {
        return;
    }
    best[x][y]=cost;
    if(x==n&&y==n)
    {
        ans=min(ans,cost);
        return;
    }
    for(int i=0;i<4;i++)
    {
        int xx=x+dx[i];
        int yy=y+dy[i];
        if(vis[xx][yy]||xx<1||xx>n||yy<1||yy>n)
        {
            continue;
        }
        if(mp[xx][yy]!=0)
        {
            vis[xx][yy]=1;
            dfs(xx,yy,cost+(mp[xx][yy]!=mp[x][y]),false);
            vis[xx][yy]=0;
        }
        else if(!flag)
        {
            vis[xx][yy]=1;
            mp[xx][yy]=mp[x][y];
            dfs(xx,yy,cost+2,true);
            vis[xx][yy]=0;
            mp[xx][yy]=0;
        }
    }
}
int main()
{
    memset(best,0x3f,sizeof(best));
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int x,y,c;
        scanf("%d%d%d",&x,&y,&c);
        mp[x][y]=c+1;
    }
    dfs(1,1,0,false);
    printf("%d",(ans==INT_MAX?-1:ans));
    return 0;
}
